object Main { def solveCase(s: String): Int = { val stack = collection.mutable.ArrayBuffer[Int](-1); var best = 0; for (i <- 0 until s.length) { if (s(i) == '(') stack += i else { stack.remove(stack.length - 1); if (stack.isEmpty) stack += i else best = math.max(best, i - stack.last) } }; best }
  def main(args: Array[String]): Unit = { val lines = io.Source.stdin.getLines().toArray; if (lines.nonEmpty) { var idx = 0; val t = lines(idx).trim.toInt; idx += 1; val out = collection.mutable.ArrayBuffer[String](); for (_ <- 0 until t) { val n = if (idx < lines.length) lines(idx).trim.toInt else 0; idx += 1; val s = if (n > 0 && idx < lines.length) { val v = lines(idx); idx += 1; v } else ""; out += solveCase(s).toString }; print(out.mkString("\n")) } } }
